897	ngx_open_file_t *
898	ngx_conf_open_file(ngx_cycle_t *cycle, ngx_str_t *name)
899	{
900	    ngx_str_t         full;
901	    ngx_uint_t        i;
902	    ngx_list_part_t  *part;
903	    ngx_open_file_t  *file;
904	
905	#if (NGX_SUPPRESS_WARN)
906	    ngx_str_null(&full);
907	#endif
908	
909	    if (name->len) {
910	        full = *name;
911	
912	        if (ngx_conf_full_name(cycle, &full, 0) != NGX_OK) {
913	            return NULL;
914	        }
915	
916	        part = &cycle->open_files.part;
917	        file = part->elts;
918	
919	        for (i = 0; /* void */ ; i++) {
920	
921	            if (i >= part->nelts) {
922	                if (part->next == NULL) {
923	                    break;
924	                }
925	                part = part->next;
926	                file = part->elts;
927	                i = 0;
928	            }
929	
930	            if (full.len != file[i].name.len) {
931	                continue;
932	            }
933	
934	            if (ngx_strcmp(full.data, file[i].name.data) == 0) {
935	                return &file[i];
936	            }
937	        }
938	    }
939	
940	    file = ngx_list_push(&cycle->open_files);
941	    if (file == NULL) {
942	        return NULL;
943	    }
944	
945	    if (name->len) {
946	        file->fd = NGX_INVALID_FILE;
947	        file->name = full;
948	
949	    } else {
950	        file->fd = ngx_stderr;
951	        file->name = *name;
952	    }
953	
954	    file->flush = NULL;
955	    file->data = NULL;
956	
957	    return file;
958	}
